function getDescription(item) {
  const n = item.name;
  const prop = item.property || 'CSS';
  if (n.startsWith('bg-')) return `Aplica color o configuración de fondo.`;
  if (n.startsWith('text-')) return `Aplica estilo de texto.`;
  if (n.startsWith('border')) return `Aplica configuración de borde.`;
  if (n.startsWith('p-') || n.startsWith('px-') || n.startsWith('py-') || n.startsWith('pt-') || n.startsWith('pr-') || n.startsWith('pb-') || n.startsWith('pl-')) return `Aplica padding.`;
  if (n.startsWith('m-') || n.startsWith('mx-') || n.startsWith('my-') || n.startsWith('mt-') || n.startsWith('mr-') || n.startsWith('mb-') || n.startsWith('ml-') || n.startsWith('neg-m')) return `Aplica margin.`;
  if (n.startsWith('w-') || n.startsWith('h-') || n.startsWith('min-') || n.startsWith('max-') || n.startsWith('size-')) return `Controla tamaño del elemento.`;
  if (n.startsWith('grid') || n.startsWith('col-') || n.startsWith('row-')) return `Se usa con CSS Grid.`;
  if (n.includes('flex') || n.startsWith('justify') || n.startsWith('items') || n.startsWith('content') || n.startsWith('self')) return `Se usa con Flexbox.`;
  return `Utilidad CSS para $visibility.`;
}

function copy(text) {
  navigator.clipboard?.writeText(text);
}

function renderSidebar() {
  const total = DS_CLASSES.length;
  const allBtn = document.createElement('button');
  allBtn.className = 'nav-item active';
  allBtn.innerHTML = `<span>Todas</span><b>${total}</b>`;
  allBtn.onclick = () => setRegion('Todas');
  sidebar.appendChild(allBtn);

  DS_REGIONS.forEach(region => {
    const qty = DS_CLASSES.filter(c => c.region === region).length;
    const btn = document.createElement('button');
    btn.className = 'nav-item';
    btn.dataset.region = region;
    btn.innerHTML = `<span>${region}</span><b>${qty}</b>`;
    btn.onclick = () => setRegion(region);
    sidebar.appendChild(btn);
  });
}

function setRegion(region) {
  activeRegion = region;
  document.querySelectorAll('.nav-item').forEach(btn => {
    const label = btn.dataset.region || 'Todas';
    btn.classList.toggle('active', label === region);
  });
  renderResults();
}

function matches(item, q) {
  if (!q) return true;
  const haystack = `${item.name} ${item.region} ${item.css} ${item.property}`.toLowerCase();
  return haystack.includes(q.toLowerCase());
}

function renderResults() {
  const q = search.value.trim();
  let list = DS_CLASSES.filter(item => activeRegion === 'Todas' || item.region === activeRegion);
  list = list.filter(item => matches(item, q));

  count.textContent = `${list.length} clases`;
  regionTitle.textContent = activeRegion === 'Todas' ? 'Todas las utilidades' : activeRegion;
  $('#regionDescription').textContent = activeRegion === 'Todas'
    ? 'Buscá por nombre de clase, propiedad CSS o región.'
    : (regionDescriptions[activeRegion] || 'Utilidades de esta región.');

  results.innerHTML = '';
  if (!list.length) {
    results.innerHTML = `<div class="empty">No encontré clases con ese filtro.</div>`;
    return;
  }

  list.forEach(item => {
    const card = document.createElement('article');
    card.className = 'class-card';
    card.innerHTML = `
      <div class="class-card-header">
        <div>
          <span class="badge">${item.region}</span>
          <h3>.${item.name}</h3>
          <p>${getDescription(item)}</p>
        </div>
        <button class="copy-btn" data-copy='${item.usage}'>Copiar clase</button>
      </div>
      <div class="preview">${item.sample}</div>
      <div class="code-grid">
        <div>
          <label>Uso</label>
          <pre><code>${escapeHtml(item.usage)}</code></pre>
        </div>
        <div>
          <label>CSS</label>
          <pre><code>.${escapeHtml(item.name)} { ${escapeHtml(item.css)} }</code></pre>
        </div>
      </div>
    `;
    card.querySelector('.copy-btn').onclick = () => copy(item.usage);
    results.appendChild(card);
  });
}

function escapeHtml(str) {
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

search.addEventListener('input', renderResults);
renderSidebar();
renderResults();
